                { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Inorder (LNR): для BST даёт отсортированный порядок." }] }] },
                { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Postorder (LRN): сначала дети, затем узел (удобно для удаления/подсчёта)." }] }] }
              ]
