{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"В вебе «узел» чаще всего про DOM Node (Element/Text/Comment/Document)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обходы: DFS и BFS; сложность O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не путайте с Node.js."}]}]}]}]}

