          ]
        },
        {
          "type": "listItem",
          "content": [
            {
              "type": "paragraph",
              "content": [
                {
                  "type": "text",
                  "text": "Как связана высота и сбалансированность? Чем меньше высота при фиксированном n, тем дерево \"сбалансированнее\"; идеальная цель — O(log n)."
                }
              ]
            }
          ]
        }
      ]
    }
  ]
}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Бинарное дерево — это структура данных, в которой каждый узел имеет не более двух детей: левого и правого. Оно служит основой для целого ряда структур (двоичное дерево поиска, куча), используется для хранения иерархий и эффективного выполнения операций поиска/вставки/удаления при соблюдении дополнительных свойств."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Определение и интуиция"}]},{"type":"paragraph","content":[{"type":"text","text":"Бинарное (двоичное) дерево — это связная ациклическая иерархическая структура из узлов, где у каждого узла не более двух потомков. Каждый узел хранит значение и ссылки на левого и правого ребёнка. В общем случае бинарное дерево не накладывает ограничений на порядок значений — порядок задаётся только в специализированных вариантах (например, в двоичном дереве поиска)."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Термины и свойства"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Узел, корень, ребро, лист: базовые части дерева. Лист — узел без детей."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Глубина узла — расстояние (число рёбер) от корня; высота узла — длина максимального пути до листа; высота дерева — высота корня; размер — число узлов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Классификации: идеальное (perfect) — все уровни полностью заполнены; полное (complete) — все уровни, кроме последнего, полны, последний заполняется слева направо; строгое (full) — у каждого узла либо 0, либо 2 ребёнка; сбалансированное — высота O(log n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Специализации: двоичное дерево поиска (BST) — все ключи в левом поддереве < ключ узла < все ключи в правом поддереве; куча (heap) — у родителя значение не меньше/не больше (max/min) значений детей, но относительный порядок левого/правого не определён."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Представление в памяти: указательное (узлы с ссылками) — универсально; массивное — эффективно для полных/почти полных деревьев: для индекса i: left = 2i + 1, right = 2i + 2, parent = ⌊(i − 1) / 2⌋."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Операции и обходы"}]},{"type":"orderedList","attrs":{"order":1},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Preorder (N-L-R): сначала узел, затем левое и правое поддерево. Полезно для копирования/сериализации."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Inorder (L-N-R): левое, узел, правое. В BST даёт отсортированную последовательность."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Postorder (L-R-N): левое, правое, узел. Полезно для удаления/вычисления выражений (деревья выражений)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Level-order (BFS): по уровням слева направо. Подходит для задач, где важна “ширина” (напр., поиск кратчайшего пути по рёбрам одинаковой стоимости)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример: построение дерева и обходы (JavaScript)"}]},{"type":"codeBlock","content":[{"type":"text","text":"class Node {
  constructor(val, left = null, right = null) {
    this.val = val;
    this.left = left;
    this.right = right;
  }
}

// Пример дерева (также корректное BST):
//         8
//       /   \
//      3     10
//     / \      \
//    1   6      14
//       / \    /
//      4   7  13
const root = new Node(
  8,
  new Node(3, new Node(1), new Node(6, new Node(4), new Node(7))),
  new Node(10, null, new Node(14, new Node(13), null))
);

function preorder(node, res = []) {
  if (!node) return res;
  res.push(node.val);
  preorder(node.left, res);
  preorder(node.right, res);
  return res;
}

function inorder(node, res = []) {
  if (!node) return res;
  inorder(node.left, res);
  res.push(node.val);
  inorder(node.right, res);
  return res;
}

function postorder(node, res = []) {
  if (!node) return res;
  postorder(node.left, res);
  postorder(node.right, res);
  res.push(node.val);
  return res;
}

function levelOrder(root) {
  if (!root) return [];
  const res = [], q = [root];
  while (q.length) {
    const n = q.shift();
    res.push(n.val);
    if (n.left) q.push(n.left);
    if (n.right) q.push(n.right);
  }
  return res;
}

console.log('Preorder:', preorder(root).join(' '));
console.log('Inorder:', inorder(root).join(' '));
console.log('Postorder:', postorder(root).join(' '));
console.log('Level-order:', levelOrder(root).join(' '));"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"BST: вставка и поиск (JavaScript)"}]},{"type":"codeBlock","content":[{"type":"text","text":"function insert(root, val) {
  if (!root) return new Node(val);
  if (val < root.val) root.left = insert(root.left, val);
  else root.right = insert(root.right, val);
  return root;
}

function search(root, val) {
  let cur = root;
  while (cur) {
    if (val === cur.val) return true;
    cur = val < cur.val ? cur.left : cur.right;
  }
  return false;
}

let bst = null;
bst = insert(bst, 8);
[3, 10, 1, 6, 14, 4, 7, 13].forEach(v => (bst = insert(bst, v)));
console.log('Search 7:', search(bst, 7)); // true
console.log('Search 2:', search(bst, 2)); // false"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Проверка свойств: валидность BST и баланс"}]},{"type":"codeBlock","content":[{"type":"text","text":"function isValidBST(node, min = -Infinity, max = Infinity) {
  if (!node) return true;
  if (node.val <= min || node.val >= max) return false;
  return (
    isValidBST(node.left, min, node.val) &&
    isValidBST(node.right, node.val, max)
  );
}

function isBalanced(root) {
  function height(node) {
    if (!node) return 0;
    const lh = height(node.left);
    if (lh === -1) return -1;
    const rh = height(node.right);
    if (rh === -1) return -1;
    if (Math.abs(lh - rh) > 1) return -1;
    return Math.max(lh, rh) + 1;
  }
  return height(root) !== -1;
}

console.log('Valid BST:', isValidBST(bst));
console.log('Balanced:', isBalanced(bst));"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Диаграмма и результаты обходов"}]},{"type":"codeBlock","content":[{"type":"text","text":"Дерево:
