        {
          "type": "text",
          "text": "// Узлы бинарного дерева\nclass Node {\n  constructor(val, left = null, right = null) {\n    this.val = val;\n    this.left = left;\n    this.right = right;\n  }\n}\n\n// DFS (рекурсивно)\nfunction preorder(node, res = []) { // NLR — прямой\n  if (!node) return res;\n  res.push(node.val);\n  preorder(node.left, res);\n  preorder(node.right, res);\n  return res;\n}\n\nfunction inorder(node, res = []) { // LNR — симметричный (для бинарных деревьев)\n  if (!node) return res;\n  inorder(node.left, res);\n  res.push(node.val);\n  inorder(node.right, res);\n  return res;\n}\n\nfunction postorder(node, res = []) { // LRN — обратный\n  if (!node) return res;\n  postorder(node.left, res);\n  postorder(node.right, res);\n  res.push(node.val);\n  return res;\n}\n\n// BFS (по уровням)\nfunction bfs(root) {\n  const res = [];\n  if (!root) return res;\n  const q = [root];\n  while (q.length) {\n    const node = q.shift();\n    res.push(node.val);\n    if (node.left) q.push(node.left);\n    if (node.right) q.push(node.right);\n  }\n  return res;\n}"
        }
