          "type": "text",
          "text": "function preorderIter(root) {\n  const res = [];\n  if (!root) return res;\n  const stack = [root];\n  while (stack.length) {\n    const node = stack.pop();\n    res.push(node.val);\n    if (node.right) stack.push(node.right);\n    if (node.left) stack.push(node.left);\n  }\n  return res;\n}\n\nfunction inorderIter(root) {\n  const res = [];\n  const stack = [];\n  let cur = root;\n  while (cur || stack.length) {\n    while (cur) {\n      stack.push(cur);\n      cur = cur.left;\n    }\n    cur = stack.pop();\n    res.push(cur.val);\n    cur = cur.right;\n  }\n  return res;\n}\n\nfunction postorderIter(root) {\n  const res = [];\n  if (!root) return res;\n  const s1 = [root];\n  const s2 = [];\n  while (s1.length) {\n    const node = s1.pop();\n    s2.push(node);\n    if (node.left) s1.push(node.left);\n    if (node.right) s1.push(node.right);\n  }\n  while (s2.length) {\n    res.push(s2.pop().val);\n  }\n  return res;\n}\n\n// BFS (по уровням)\nfunction bfsIter(root) {\n  return bfs(root);\n}"
