function TreeNode(val, left = null, right = null) {
  this.val = val;
  this.left = left;
  this.right = right;
}

// Preorder: N-L-R
function preorder(root) {
  const res = [];
  function dfs(node) {
    if (!node) return;
    res.push(node.val);      // N
    dfs(node.left);          // L
    dfs(node.right);         // R
  }
  dfs(root);
  return res;
}

// Пример
const root = new TreeNode(1,
  new TreeNode(2,
    new TreeNode(4),
    new TreeNode(5)
  ),
  new TreeNode(3,
    null,
    new TreeNode(6)
  )
);

console.log(preorder(root)); // [1, 2, 4, 5, 3, 6]"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Итеративная реализация (стек)"}]},{"type":"codeBlock","content":[{"type":"text","text":"function preorderIterative(root) {
  if (!root) return [];
  const res = [];
  const stack = [root];
  while (stack.length) {
    const node = stack.pop();
    res.push(node.val);           // посещаем узел
    if (node.right) stack.push(node.right); // сначала вправо
    if (node.left) stack.push(node.left);   // затем влево — чтобы левый был сверху стека
  }
  return res;
}

// Проверка
console.log(preorderIterative(root)); // [1, 2, 4, 5, 3, 6]"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Отличия от других обходов"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Inorder (L-N-R): левое — корень — правое. Для BST даёт отсортированную последовательность."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Postorder (L-R-N): левое — правое — корень. Удобен для удаления/освобождения ресурсов снизу вверх."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Preorder (N-L-R): корень — левое — правое. Позволяет «сначала понять структуру», затем углубляться в поддеревья."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сложность и память"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Время: O(n) — каждый узел посещается один раз."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(h) для стека рекурсии/итерации; в худшем случае (линейное дерево) — O(n)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Частые ошибки и тонкости"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Забыть обработать текущий узел до рекурсии (это уже будет inorder/postorder)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"В итеративной версии перепутать порядок push: нужно сначала push правого, затем левого ребёнка."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не учитывать null-узлы при сериализации (для однозначного восстановления дерева null надо явно фиксировать)."}]}]}]}]}

