          "type": "text",
          "text": "class TreeNode {\n  constructor(val, left = null, right = null) {\n    this.val = val;\n    this.left = left;\n    this.right = right;\n  }\n}\n\nfunction inorderRecursive(root) {\n  const res = [];\n  function dfs(node) {\n    if (!node) return;\n    dfs(node.left);\n    res.push(node.val);\n    dfs(node.right);\n  }\n  dfs(root);\n  return res;\n}\n\n// Пример использования\nconst root = new TreeNode(\n  4,\n  new TreeNode(2, new TreeNode(1), new TreeNode(3)),\n  new TreeNode(6, new TreeNode(5), new TreeNode(7))\n);\n\nconsole.log(inorderRecursive(root)); // [1, 2, 3, 4, 5, 6, 7]"
