          "type": "text",
          "text": "function inorderIterative(root) {\n  const res = [];\n  const stack = [];\n  let curr = root;\n\n  while (curr || stack.length) {\n    // доходим до самого левого узла\n    while (curr) {\n      stack.push(curr);\n      curr = curr.left;\n    }\n    // обрабатываем вершину и переходим вправо\n    curr = stack.pop();\n    res.push(curr.val);\n    curr = curr.right;\n  }\n\n  return res;\n}"
