          "type": "text",
          "text": "function inorderMorris(root) {\n  const res = [];\n  let curr = root;\n\n  while (curr) {\n    if (!curr.left) {\n      res.push(curr.val);\n      curr = curr.right;\n    } else {\n      // находим предшественника (самый правый в левом поддереве)\n      let pre = curr.left;\n      while (pre.right && pre.right !== curr) {\n        pre = pre.right;\n      }\n      if (!pre.right) {\n        // создаём «нить» обратно к текущему узлу\n        pre.right = curr;\n        curr = curr.left;\n      } else {\n        // удаляем «нить» и посещаем текущий\n        pre.right = null;\n        res.push(curr.val);\n        curr = curr.right;\n      }\n    }\n  }\n\n  return res;\n}"
