        {
          "type": "text",
          "text": "function preorderIter(root) {\n  if (!root) return [];\n  const res = [];\n  const stack = [root];\n  while (stack.length) {\n    const node = stack.pop();\n    res.push(node.val);            // pre-обработка\n    if (node.right) stack.push(node.right); // кладём правоГО первым\n    if (node.left) stack.push(node.left);   // чтобы левый достался раньше\n  }\n  return res;\n}\n\n// Пример структуры узла:\n// { val: number, left: Node|null, right: Node|null }"
        }
