      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "function inorderIter(root) {\n  const res = [];\n  const stack = [];\n  let curr = root;\n  while (curr || stack.length) {\n    while (curr) {           // идём по левым веткам, запоминая путь\n      stack.push(curr);\n      curr = curr.left;\n    }\n    curr = stack.pop();      // левое поддерево исчерпано — обрабатываем узел\n    res.push(curr.val);\n    curr = curr.right;       // затем идём в правое поддерево\n  }\n  return res;\n}"
        }
      ]
    },
    {
      "type": "heading",
