      "content": [{ "type": "text", "text": "3) DFS по дереву: postorder (left-right-node) через флаг состояния" }]
    },
    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "function postorderIter(root) {\n  const res = [];\n  if (!root) return res;\n  const stack = [{ node: root, visited: false }];\n  while (stack.length) {\n    const { node, visited } = stack.pop();\n    if (!node) continue;\n    if (visited) {\n      res.push(node.val); // post-обработка\n    } else {\n      // Кладём маркер на повторный заход после детей\n      stack.push({ node, visited: true });\n      if (node.right) stack.push({ node: node.right, visited: false });\n      if (node.left) stack.push({ node: node.left, visited: false });\n    }\n  }\n  return res;\n}"
        }
