        {
          "type": "text",
          "text": "function dfsGraph(adj, start) {\n  // adj: Map<Vertex, Vertex[]> или объект { v: [u1, u2, ...] }\n  const visited = new Set();\n  const stack = [start];\n  const order = [];\n  while (stack.length) {\n    const v = stack.pop();\n    if (visited.has(v)) continue; // важно избегать циклов\n    visited.add(v);\n    order.push(v);\n    const neighbors = (adj.get ? adj.get(v) : adj[v]) || [];\n    for (let i = neighbors.length - 1; i >= 0; i--) {\n      const u = neighbors[i];\n      if (!visited.has(u)) stack.push(u);\n    }\n  }\n  return order;\n}"
        }
      ]
