        {
          "type": "text",
          "text": "function dfsIterGeneric(start) {\n  // Кадр хранит узел и фазу: 'enter' (до детей) или 'exit' (после детей)\n  const stack = [{ node: start, state: 'enter' }];\n  while (stack.length) {\n    const frame = stack.pop();\n    const { node, state } = frame;\n    if (!node) continue;\n    if (state === 'enter') {\n      // 1) pre-обработка\n      // ...\n      // 2) Планируем post-обработку\n      stack.push({ node, state: 'exit' });\n      // 3) Кладём детей в обратном порядке, чтобы первый логический ребёнок пошёл первым\n      const children = node.children || [];\n      for (let i = children.length - 1; i >= 0; i--) {\n        stack.push({ node: children[i], state: 'enter' });\n      }\n    } else {\n      // post-обработка\n      // ...\n    }\n  }\n}\n"
        }
