          "type": "text",
          "text": "function bfs(adj, start) {\n  const n = adj.length;\n  const dist = Array(n).fill(Infinity);\n  const parent = Array(n).fill(-1);\n  const visited = Array(n).fill(false);\n  const q = [];\n  let head = 0; // реализация очереди через массив и указатель головы\n\n  q.push(start);\n  visited[start] = true;\n  dist[start] = 0;\n\n  while (head < q.length) {\n    const u = q[head++];\n    for (const v of adj[u]) {\n      if (!visited[v]) {\n        visited[v] = true;        // отмечаем при добавлении\n        parent[v] = u;            // запоминаем дерево BFS\n        dist[v] = dist[u] + 1;    // расстояние по слоям\n        q.push(v);\n      }\n    }\n  }\n  return { dist, parent, visited };\n}\n"
